const body = $input.first().json;
let chatId='', userId='', updateType='', text='', callbackData='', messageId='', callbackQueryId='';
if (body.message) {
  chatId = String(body.message.chat.id);
  userId = String(body.message.from.id);
  messageId = body.message.message_id;
  text = body.message.text || '';
  updateType = (text === '/start' || text.startsWith('/start ')) ? 'start' : 'message';
} else if (body.callback_query) {
  const cb = body.callback_query;
  chatId = String(cb.message.chat.id);
  userId = String(cb.from.id);
  callbackData = cb.data || '';
  callbackQueryId = cb.id || '';
  updateType = 'callback_query';
}
return [{ json: { chatId, userId, updateType, text, callbackData, messageId, callbackQueryId } }];

const moscowOffset = 3 * 60;
const now = new Date();
const moscowNow = new Date(now.getTime() + moscowOffset * 60000);

let chatId = '';
let userText = '';

try {
  const pu = $('Parse Update').first().json;
  chatId = pu.chatId || '';
  userText = pu.text || '';
} catch(e) {}

try {
  const cb = $('Parse Callback').first().json;
  if (cb && cb.isMenuAction && cb.text) {
    userText = cb.text;
    if (cb.chatId) chatId = cb.chatId;
  }
} catch(e) {}

const currentDateTime = moscowNow.toLocaleString('ru-RU', {
  weekday:'long', year:'numeric', month:'long', day:'numeric',
  hour:'2-digit', minute:'2-digit', timeZone:'Europe/Moscow'
});

// Не передаём список занятых слотов — AI не должен предлагать даты
return [{ json: { chatId, userText, currentDateTime } }];

const rawOutput = $input.first().json.output || '';

// Извлечь команды
const bookMatch = rawOutput.match(/%%BOOK%%\s*({[\s\S]*?})\s*%%END%%/);
const cancelMatch = rawOutput.match(/%%CANCEL%%\s*({[\s\S]*?})\s*%%END%%/);

// Очистить текст от команд
let replyText = rawOutput
  .replace(/%%BOOK%%[\s\S]*?%%END%%/g, '')
  .replace(/%%CANCEL%%[\s\S]*?%%END%%/g, '')
  .trim();

let command = 'none';
let commandData = {};

if (bookMatch) {
  try {
    commandData = JSON.parse(bookMatch[1]);
    commandData.chatId = $('Parse Update').first().json.chatId;
    command = 'book';
  } catch(e) { console.log('Book parse error:', e.message); }
}
if (cancelMatch) {
  try {
    commandData = JSON.parse(cancelMatch[1]);
    commandData.chatId = $('Parse Update').first().json.chatId;
    command = 'cancel';
  } catch(e) { console.log('Cancel parse error:', e.message); }
}

return [{ json: { command, commandData, replyText } }];

const d = $input.first().json.commandData;
const chatId = d.chatId || $('Parse Update').first().json.chatId;
const name = d.name || 'Клиент';
const date = d.date; // YYYY-MM-DD
const time = d.time; // HH:MM

// Вычислить конец занятия (+60 мин)
const [h, m] = time.split(':').map(Number);
const endH = h + 1;
const endTime = String(endH).padStart(2,'0') + ':' + String(m).padStart(2,'0');

// ISO строки в UTC+3
const startISO = date + 'T' + time + ':00+03:00';
const endISO   = date + 'T' + endTime + ':00+03:00';

// ID записи
const apptId = 'appt_' + Date.now();

// Форматированная дата для уведомлений
const dt = new Date(startISO);
const formatted = dt.toLocaleString('ru-RU', {weekday:'long',day:'numeric',month:'long',hour:'2-digit',minute:'2-digit',timeZone:'Europe/Moscow'});

return [{ json: { chatId, name, date, time, endTime, startISO, endISO, apptId, formatted } }];

