const d = $input.first().json.commandData;
const date = d.date; // YYYY-MM-DD
const time = d.time || '00:00';
const chatId = d.chatId || $('Parse Update').first().json.chatId;

// Диапазон поиска — весь день
const timeMin = date + 'T00:00:00+03:00';
const timeMax = date + 'T23:59:59+03:00';

return [{ json: { date, time, chatId, timeMin, timeMax } }];

const events = $input.all();
const cancelData = $('Prep Cancel').first().json;
const chatId = cancelData.chatId;
const targetDate = cancelData.date;  // YYYY-MM-DD
const targetTime = cancelData.time;  // HH:MM

let foundEventId = '';
let foundSummary = '';

for (const ev of events) {
  const item = ev.json;
  const desc = item.description || '';
  const startStr = item.start && (item.start.dateTime || item.start.date);
  if (!startStr) continue;

  const startD = new Date(startStr);
  // Дата события в московском времени YYYY-MM-DD
  const moscowDate = startD.toLocaleDateString('sv-SE', {timeZone: 'Europe/Moscow'});
  const moscowTime = startD.toLocaleTimeString('ru-RU', {hour:'2-digit', minute:'2-digit', timeZone:'Europe/Moscow'});

  const hasChatId = desc.includes('telegram_id:' + chatId) || desc.includes('telegram_id: ' + chatId);
  const matchDate = moscowDate === targetDate;
  const matchTime = !targetTime || moscowTime === targetTime;

  if (hasChatId && matchDate && matchTime) {
    foundEventId = item.id;
    foundSummary = item.summary || '';
    break;
  }
}

// 'нашли' или 'нет' — для IF ноды
const status = foundEventId ? 'found' : 'not_found';
return [{ json: { foundEventId, foundSummary, status, chatId, cancelDate: targetDate, cancelTime: targetTime } }];

const token = '8280013265:AAGqlHlsmN5_-wTBmlCJ9A4bB4fzl9AIGMs';
const parseOutput = $('Parse Output').first().json;
const text = parseOutput.replyText || '';

let chatId = '';
try { chatId = $('Parse Update').first().json.chatId || ''; } catch(e) {}
if (!chatId) { try { chatId = $('Parse Callback').first().json.chatId || ''; } catch(e) {} }

if (!chatId || !text) return [{ json: { skipped: true } }];

// Отвечаем на callbackQuery (чтобы кнопка не крутилась)
try {
  const cqId = $('Parse Callback').first().json.callbackQueryId;
  if (cqId) {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${token}/answerCallbackQuery`,
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ callback_query_id: cqId, text: '' })
    });
  }
} catch(e) {}

// Если AI просит подтвердить — добавляем кнопки
const lc = text.toLowerCase();
const needsConfirm = lc.includes('подтверди');

const body = { chat_id: chatId, text: text, parse_mode: 'HTML' };

if (needsConfirm) {
  body.reply_markup = { inline_keyboard: [[
    { text: '✅ Подтверждаю', callback_data: 'menu_confirm' },
    { text: '❌ Нет', callback_data: 'cancel_abort' }
  ]] };
}

await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${token}/sendMessage`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body)
});

return [{ json: { sent: true, hadConfirmButtons: needsConfirm } }];

const item = $input.first().json;
const chatId = item.chatId || '';
const callbackData = item.callbackData || '';
const callbackQueryId = item.callbackQueryId || '';

// Кнопки меню
const menuMap = {
  'menu_book': 'Хочу записаться',
  'menu_cancel': 'Хочу отменить запись',
  'menu_list': 'Покажи мои записи',
  'menu_confirm': 'Подтверждаю'
};
if (menuMap[callbackData]) {
  return [{ json: { chatId, callbackQueryId, isMenuAction: true, text: menuMap[callbackData] } }];
}

// Подтверждение отмены (confirm_cancel_DATE_TIME)
if (callbackData.startsWith('confirm_cancel_')) {
  const rest = callbackData.replace('confirm_cancel_', '');
  const parts = rest.split('_');
  const cancelDate = parts[0] || '';
  const cancelTime = (parts[1] || '').replace('-', ':');
  return [{ json: { chatId, callbackQueryId, isConfirmCancel: true, cancelDate, cancelTime } }];
}

// Кнопка отмены (cancel_DATE_TIME)
if (callbackData.startsWith('cancel_')) {
  const rest = callbackData.replace('cancel_', '');
  const parts = rest.split('_');
  const cancelDate = parts[0] || '';
  const cancelTime = (parts[1] || '').replace('-', ':');
  if (cancelDate && cancelDate !== 'abort') {
    return [{ json: { chatId, callbackQueryId, isCancelAction: true, cancelDate, cancelTime } }];
  }
  return [{ json: { chatId, callbackQueryId, isNoop: true } }];
}

// Отзыв (1-5 звёзд)
const rating = parseInt(callbackData);
if (rating >= 1 && rating <= 5) {
  const stars = '⭐'.repeat(rating);
  return [{ json: { chatId, callbackQueryId, rating, stars, apptDate: '', isMenuAction: false } }];
}

return [{ json: { chatId, callbackData, callbackQueryId, isMenuAction: false } }];

const events = $input.all();
const result = [];
for (const ev of events) {
  const item = ev.json;
  if (!item.start) continue;
  const desc = item.description || '';
  const match = desc.match(/telegram_id:\s*(\d+)/);
  if (!match) continue;
  const chatId = match[1];
  const startStr = item.start.dateTime || item.start.date;
  const startDate = new Date(startStr);
  const timeStr = startDate.toLocaleTimeString('ru-RU', {hour:'2-digit', minute:'2-digit', timeZone:'Europe/Moscow'});
  const dateStr = startDate.toLocaleDateString('ru-RU', {weekday:'short', day:'numeric', month:'long', timeZone:'Europe/Moscow'});
  const rawDate = startDate.toLocaleDateString('ru-RU', {timeZone:'Europe/Moscow'}).split('.').reverse().join('-');
  result.push({ json: { chatId, timeStr, dateStr, rawDate } });
}
return result.length > 0 ? result : [{ json: { skip: true } }];

