const rows = $input.all();
const today = new Date().toLocaleDateString('ru-RU', {timeZone:'Europe/Moscow'}).split('.').reverse().join('-');
// today format: YYYY-MM-DD

const result = [];
for (const row of rows) {
  const r = row.json;
  if (!r.user_id || !r.datetime) continue;
  if (r.status === 'cancelled') continue;
  if (r.feedback_sent === '1' || r.feedback_sent === 1) continue;

  // Проверить что datetime содержит сегодняшнюю дату
  const dt = r.datetime || '';
  const rowDate = dt.split(' ')[0]; // "YYYY-MM-DD"

  if (rowDate === today) {
    const timeStr = dt.split(' ')[1] || '';
    result.push({ json: {
      chatId: r.user_id.toString(),
      name: r.child_name || 'клиент',
      date: rowDate,
      time: timeStr,
      apptId: r.appointment_id
    }});
  }
}

return result.length > 0 ? result : [{ json: { skip: true } }];

