const token = '8280013265:AAGqlHlsmN5_-wTBmlCJ9A4bB4fzl9AIGMs';
const cb = $('Parse Callback').first().json;
const chatId = cb.chatId || '';
const callbackQueryId = cb.callbackQueryId || '';

// mode: 'cancel' = показать кнопки отмены, 'list' = показать текстовый список
const mode = (cb.text === 'Покажи мои записи') ? 'list' : 'cancel';

// Ответить на callbackQuery
if (callbackQueryId) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${token}/answerCallbackQuery`,
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ callback_query_id: callbackQueryId, text: '' })
    });
  } catch(e) {}
}

const now = new Date();
const rows = $input.all();

const upcoming = rows
  .filter(r => {
    const j = r.json;
    if (!j || !j.user_id) return false;
    if (String(j.user_id) !== String(chatId)) return false;
    if (j.status !== 'active') return false;
    if (!j.datetime) return false;
    const dt = new Date(j.datetime.replace(' ', 'T') + ':00+03:00');
    return dt > now;
  })
  .sort((a, b) => {
    const da = new Date(a.json.datetime.replace(' ', 'T') + ':00+03:00');
    const db = new Date(b.json.datetime.replace(' ', 'T') + ':00+03:00');
    return da - db;
  });

if (upcoming.length === 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${token}/sendMessage`,
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({ chat_id: chatId, text: '💭 У вас нет активных записей.' })
  });
  return [{ json: { done: true, count: 0 } }];
}

if (mode === 'list') {
  // Текстовый список записей
  let text = '📋 <b>Ваши записи:</b>\n\n';
  for (const r of upcoming) {
    const j = r.json;
    const dt = new Date(j.datetime.replace(' ', 'T') + ':00+03:00');
    const dateStr = dt.toLocaleDateString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Moscow' });
    const timeStr = dt.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Moscow' });
    const name = j.child_name ? ' — ' + j.child_name : '';
    text += `📅 ${dateStr} в ${timeStr}${name}\n`;
  }
  text += '\nДля отмены нажмите кнопку «Отменить».';
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${token}/sendMessage`,
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
  });
} else {
  // Inline кнопки для отмены
  const buttons = upcoming.map(r => {
    const j = r.json;
    const isoDate = j.datetime.slice(0, 10);
    const rawTime = j.datetime.slice(11, 16);
    const dt = new Date(j.datetime.replace(' ', 'T') + ':00+03:00');
    const dateStr = dt.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', timeZone: 'Europe/Moscow' });
    const timeStr = dt.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Moscow' });
    const name = j.child_name ? ' — ' + j.child_name : '';
    const timeCb = rawTime.replace(':', '-');
    return [{ text: '📅 ' + dateStr + ', ' + timeStr + name,
              callback_data: 'cancel_' + isoDate + '_' + timeCb }];
  });
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${token}/sendMessage`,
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({
      chat_id: chatId,
      text: 'Выберите запись для отмены:',
      reply_markup: { inline_keyboard: buttons }
    })
  });
}

return [{ json: { done: true, count: upcoming.length, mode } }];

