const bookData = $('Prep Book').first().json;
const events = $input.all();
const targetDate = bookData.date;
const targetTime = bookData.time;

const [h, m] = targetTime.split(':').map(Number);
const dt = new Date(bookData.startISO);
const dayOfWeek = dt.getDay();

if (dayOfWeek === 0) {
  return [{ json: { ...bookData, slotFree: false, slotTakenMessage: 'Воскресенье - выходной. Запись Пн-Сб.' } }];
}

if (h < 9 || h > 17 || (h === 17 && m > 0)) {
  return [{ json: { ...bookData, slotFree: false, slotTakenMessage: 'Запись доступна с 9:00 до 17:00. Напишите другое время.' } }];
}

const now = new Date();
const moscowNow = new Date(now.toLocaleString('en-US', {timeZone: 'Europe/Moscow'}));
if (dt < moscowNow) {
  return [{ json: { ...bookData, slotFree: false, slotTakenMessage: 'Это время уже прошло. Выберите будущую дату/время.' } }];
}

let isTaken = false;
for (const ev of events) {
  const item = ev.json;
  if (!item || !item.start) continue;
  const startStr = item.start.dateTime || item.start.date;
  if (!startStr) continue;
  const startD = new Date(startStr);
  const moscowDate = startD.toLocaleDateString('sv-SE', {timeZone: 'Europe/Moscow'});
  const moscowTime = startD.toLocaleTimeString('ru-RU', {hour:'2-digit', minute:'2-digit', timeZone:'Europe/Moscow'});
  if (moscowDate === targetDate && moscowTime === targetTime) {
    isTaken = true;
    break;
  }
}

if (isTaken) {
  return [{ json: { ...bookData, slotFree: false, slotTakenMessage: 'К сожалению, ' + targetDate + ' в ' + targetTime + ' уже занято. Напишите другое удобное время.' } }];
}

return [{ json: { ...bookData, slotFree: true, slotTakenMessage: '' } }];
